const SPREADSHEET_ID = "\${SHEET_ID}";

function doGet(e) {
  const action = e && e.parameter ? e.parameter.action : null;
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  
  if (action === "READ_SUBMISSIONS" || action === "READ_USERS") {
    let sheet;
    if (action === "READ_SUBMISSIONS") {
      sheet = ss.getSheets()[0];
    } else {
      sheet = ss.getSheetByName("User") || ss.getSheets()[1] || ss.getSheets()[0];
    }
    
    const rows = sheet.getDataRange().getValues();
    // Convert 2D array of rows to CSV string
    const csvContent = rows.map(row => 
      row.map(cell => {
        let val = cell === null || cell === undefined ? "" : cell.toString();
        if (val.includes(",") || val.includes('"') || val.includes("\\n")) {
          val = '"' + val.replace(/"/g, '""') + '"';
        }
        return val;
      }).join(",")
    ).join("\\n");
    
    return ContentService.createTextOutput(csvContent)
      .setMimeType(ContentService.MimeType.TEXT);
  }
  
  return ContentService.createTextOutput(JSON.stringify({ status: "running", message: "Redaksillin Backend is online!" }))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const payload = JSON.parse(e.postData.contents);
    const action = payload.action; 
    const data = payload.data;
    
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheets()[0]; // Sheet ke-1 (Materi Publikasi)
    
    if (action === "CREATE") {
      sheet.appendRow([
        data.id,
        data.tanggalInput || "",
        data.tanggalRencanaTayang || "",
        data.petugasInput || "",
        data.verifikator || "",
        data.tanggalEvaluasi || "-",
        data.status || "Pending",
        data.linkDatadukung || "",
        data.catatanRevisi || "-"
      ]);
      return ContentService.createTextOutput(JSON.stringify({ success: true }))
        .setMimeType(ContentService.MimeType.JSON);
    }
    
    if (action === "UPDATE_STATUS" || action === "EDIT") {
      const rows = sheet.getDataRange().getValues();
      let found = false;
      for (let i = 1; i < rows.length; i++) {
        if (rows[i][0].toString().trim() === data.id.toString().trim()) {
          const rowNum = i + 1;
          if (data.status) sheet.getRange(rowNum, 7).setValue(data.status);
          if (data.tanggalEvaluasi) sheet.getRange(rowNum, 6).setValue(data.tanggalEvaluasi);
          if (data.catatanRevisi) sheet.getRange(rowNum, 9).setValue(data.catatanRevisi);
          if (data.tanggalRencanaTayang) sheet.getRange(rowNum, 3).setValue(data.tanggalRencanaTayang);
          if (data.linkDatadukung) sheet.getRange(rowNum, 8).setValue(data.linkDatadukung);
          found = true;
          break;
        }
      }
      return ContentService.createTextOutput(JSON.stringify({ success: found }))
        .setMimeType(ContentService.MimeType.JSON);
    }
    
    if (action === "DELETE") {
      const rows = sheet.getDataRange().getValues();
      let found = false;
      for (let i = 1; i < rows.length; i++) {
        if (rows[i][0].toString().trim() === data.id.toString().trim()) {
          sheet.deleteRow(i + 1);
          found = true;
          break;
        }
      }
      return ContentService.createTextOutput(JSON.stringify({ success: found }))
        .setMimeType(ContentService.MimeType.JSON);
    }
    
    return ContentService.createTextOutput(JSON.stringify({ success: false }))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ success: false, error: error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}`),alert("Kode Apps Script berhasil disalin!")},className:"text-[10px] font-bold text-emerald-700 hover:text-emerald-800 bg-emerald-50 hover:bg-emerald-100 px-2.5 py-1 rounded-lg border border-emerald-150 flex items-center gap-1 cursor-pointer transition-all",children:[d.jsx(UN,{className:"w-3 h-3"})," Salin Kode"]})]}),d.jsx("pre",{className:"text-[10px] font-mono bg-slate-900 text-slate-300 p-3.5 rounded-xl overflow-x-auto max-h-48 border border-slate-800 leading-relaxed select-all",children:`// Google Apps Script Code - REDAKSILLIN LIVE SYNC & READ
